#include <stdio.h>
#define MOD 1000000007
long long dp[10000001];
int main() {
    int N, K, A, B;
    scanf("%d %d %d %d", &N, &K, &A, &B);
    dp[1] = K;
    for (int i = 2; i <= N; i++) {
        long long sum = 0;
        for (int j = 1; j < i; j++) {
            sum = (sum + dp[j] * dp[i - j]) % MOD;
        }
        dp[i] = (A * dp[i - 1] + B * sum) % MOD;
    }
    printf("%lld\n", dp[N]);
    return 0;
}

